-- Generated from Chengdu Museum markdown files (with cover images)
WITH input_rows(attraction_name_zh, sort_order, name_en, name_zh, body, cover_image_path) AS (
  VALUES
  ('成都博物馆', 0, 'Main Entrance Hall', '正门大厅', '<p>The Main Entrance Hall is the entrance space and core atrium of the new Chengdu Museum building, with a soaring ceiling of tens of meters, creating a magnificent and imposing atmosphere. The hall''s design integrates modern architectural language with ancient Shu cultural elements.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_01.png'),
  ('成都博物馆', 1, 'B1F · "Man and Nature" — Behring Donation Exhibition', '负一楼·人与自然——贝林捐赠展', '<p>"Man and Nature — Behring Donation Exhibition" is located on the basement level 1 of Chengdu Museum, and is the first nature-themed exhibition since the museum''s establishment.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_02.png'),
  ('成都博物馆', 2, '2F · "From Nine Heavens Emerged Chengdu" — Chengdu in the Pre-Qin Period', '二楼·九天开出一成都——先秦时期的成都', '<p>"From nine heavens emerged a Chengdu" is taken from the Tang Dynasty poet Li Bai''s poem "Song of the Emperor''s Western Journey to the Southern Capital," with the full line reading "From nine heavens emerged a Chengdu, with ten thousand households and a thousand gates forming a picture scroll."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_03.png'),
  ('成都博物馆', 3, '2F · "Western Shu Known as Land of Abundance" — Chengdu in the Han, Wei, Jin, Southern and Northern Dynasties Period', '二楼·西蜀称天府——两汉魏晋南北朝时期的成都', '<p>The "Western Shu Known as Land of Abundance" gallery is located on the 2nd floor of Chengdu Museum, as the second part of the "Flowers Weigh Down Brocade City — Chengdu Historical and Cultural Exhibition (Ancient Period)."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_04.png'),
  ('成都博物馆', 4, '3F · "A Bustling Famous Metropolis" — Chengdu in the Sui, Tang, Five Dynasties, Song, and Yuan Period', '三楼·喧然名都会——隋唐五代宋元时期的成都', '<p>"A bustling famous metropolis" is taken from the Tang Dynasty poet Du Fu''s poem "Chengdu Fu," with the line "A bustling famous metropolis, with flutes and sheng pipes alternating."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_05.png'),
  ('成都博物馆', 5, '3F · "Red Towers Glow in the Evening" — Chengdu in the Ming and Qing Period', '三楼·丹楼生晚辉——明清时期的成都', '<p>"Red towers glow in the evening" is taken from the poem of Yang Shen, a Ming Dynasty scholar from Sichuan. The gallery is located on the 3rd floor of Chengdu Museum.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_06.png'),
  ('成都博物馆', 6, '4F · "Flowers Weigh Down Brocade City" — Chengdu Historical and Cultural Exhibition (Modern Period)', '四楼·花重锦官城——成都历史文化陈列（近世篇）', '<p>"Flowers Weigh Down Brocade City — Chengdu Historical and Cultural Exhibition (Modern Period)" is located on the 4th floor of Chengdu Museum, focusing on Chengdu''s modern history from the mid-19th century to the mid-20th century.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_07.png'),
  ('成都博物馆', 7, '4F · "Flowers Weigh Down Brocade City" — Chengdu Historical and Cultural Exhibition (Folk Customs Section)', '四楼·花重锦官城——成都历史文化陈列（民俗篇）', '<p>"Flowers Weigh Down Brocade City — Chengdu Historical and Cultural Exhibition (Folk Customs Section)" is located on the 4th floor of Chengdu Museum.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_08.png'),
  ('成都博物馆', 8, '5F · "Shadow Dance of All Phenomena" — Chinese Shadow Puppetry Exhibition', '五楼·影舞万象——中国皮影展', '<p>"Shadow Dance of All Phenomena — Chinese Shadow Puppetry Exhibition" is located on the 5th floor of Chengdu Museum. It is one of the museum''s most distinctive permanent exhibitions and the largest and finest shadow puppetry thematic exhibition in China.</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_09.png'),
  ('成都博物馆', 9, '5F · "Puppet Theater of the Great Thousand" — Chinese Puppet Exhibition', '五楼·偶戏大千——中国木偶展', '<p>"Puppet Theater of the Great Thousand — Chinese Puppet Exhibition" is located on the 5th floor of Chengdu Museum, adjacent to the "Shadow Dance of All Phenomena — Chinese Shadow Puppetry Exhibition."</p>', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_museum_sa_10.png')
), mapped_rows AS (
  SELECT CONCAT(a.id, '_sa_', LPAD((i.sort_order + 1)::text, 2, '0')) AS id, a.id AS attraction_id, i.name_en, i.name_zh, i.body, i.cover_image_path, i.sort_order
  FROM input_rows i JOIN attractions a ON a.chinese_name = i.attraction_name_zh
)
INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
SELECT id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, TRUE FROM mapped_rows
ON CONFLICT (id) DO UPDATE SET name_en=EXCLUDED.name_en, name_zh=EXCLUDED.name_zh, body=EXCLUDED.body, cover_image_path=EXCLUDED.cover_image_path, sort_order=EXCLUDED.sort_order, is_active=EXCLUDED.is_active, updated_at=NOW();
